head.script:
//
window.tailwind = window.tailwind || {};
tailwind.config = {
  darkMode: ['class', '[data-theme="dark"]'],
  theme: {
    extend: {
      colors: {
        bg: 'rgb(var(--c-bg) / <alpha-value>)',
        'bg-2': 'rgb(var(--c-bg-2) / <alpha-value>)',
        'surface-soft': 'rgb(var(--c-surface-soft) / <alpha-value>)',
        line: 'rgb(var(--c-line) / <alpha-value>)',
        fg: 'rgb(var(--c-fg) / <alpha-value>)',
        'fg-muted': 'rgb(var(--c-fg-muted) / <alpha-value>)',
        'fg-soft': 'rgb(var(--c-fg-soft) / <alpha-value>)',
        primary: {
          DEFAULT: 'rgb(var(--c-primary) / <alpha-value>)',
          600: 'rgb(var(--c-primary-600) / <alpha-value>)',
          soft: 'rgb(var(--c-primary-soft) / <alpha-value>)',
        },
        cyan: 'rgb(var(--c-cyan) / <alpha-value>)',
        gold: 'rgb(var(--c-gold) / <alpha-value>)',
      },
      fontFamily: {
        sans: ['Sora', 'Inter', 'system-ui', 'sans-serif'],
        display: ['Orbitron', 'Rajdhani', 'sans-serif'],
        head: ['Rajdhani', 'Sora', 'sans-serif'],
      },
      boxShadow: {
        soft: '0 6px 24px -8px rgba(17,24,39,0.10), 0 2px 6px -2px rgba(17,24,39,0.05)',
        card: '0 1px 2px rgba(17,24,39,0.04), 0 4px 16px -4px rgba(17,24,39,0.06)',
      },
    },
  },
};
//

body.script:
//
(function () {
  var CONFIG = {};
  try { CONFIG = JSON.parse(document.getElementById('sb-config').textContent); } catch (e) {}

  // ===== Theme =====
  var root = document.documentElement;
  var saved = localStorage.getItem('sb-theme') || 'light';
  root.setAttribute('data-theme', saved);
  function syncThemeIcons() {
    var theme = root.getAttribute('data-theme');
    var sun = document.getElementById('sb-icon-sun');
    var moon = document.getElementById('sb-icon-moon');
    if (sun && moon) {
      sun.style.display = theme === 'dark' ? 'none' : '';
      moon.style.display = theme === 'dark' ? '' : 'none';
    }
  }
  document.addEventListener('click', function (e) {
    if (e.target.closest('#sb-theme-toggle')) {
      var t = root.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
      root.setAttribute('data-theme', t);
      localStorage.setItem('sb-theme', t);
      syncThemeIcons();
    }
  });
  syncThemeIcons();

  // ===== Loader =====
  window.addEventListener('load', function () {
    setTimeout(function () {
      var el = document.getElementById('sb-loader');
      if (el) el.classList.add('hide');
    }, 200);
  });

  // ===== Scrolled navbar shadow =====
  var hdr = document.getElementById('sb-header');
  function onScroll() { if (hdr) hdr.classList.toggle('shadow-lg', window.scrollY > 30); }
  window.addEventListener('scroll', onScroll, { passive: true });

  // ===== Mobile drawer =====
  var drawer = document.getElementById('sb-drawer');
  function setDrawer(open) {
    if (!drawer) return;
    drawer.classList.toggle('hidden', !open);
    document.body.style.overflow = open ? 'hidden' : '';
  }
  document.addEventListener('click', function (e) {
    if (e.target.closest('#sb-burger')) setDrawer(true);
    if (e.target.closest('[data-close="1"]')) setDrawer(false);
  });

  // ===== Active nav link =====
  var path = location.pathname;
  document.querySelectorAll('.sb-nav-link').forEach(function (a) {
    var dp = a.getAttribute('data-path') || '';
    if (path === '/' && dp === '/') a.classList.add('active');
    else if (dp !== '/' && path.indexOf(dp) === 0) a.classList.add('active');
  });

  // ===== Year =====
  var yearEl = document.getElementById('sb-year');
  if (yearEl) yearEl.textContent = new Date().getFullYear();

  // ===== Reveal on scroll =====
  var io = ('IntersectionObserver' in window)
    ? new IntersectionObserver(function (entries) {
      entries.forEach(function (en) {
        if (en.isIntersecting) en.target.classList.add('show');
      });
    }, { rootMargin: '0px 0px -10% 0px', threshold: 0.05 })
    : null;
  function watch(el) { if (io) io.observe(el); else el.classList.add('show'); }

  // ===== Render utilities =====
  function fmtPrice(n) {
    if (n == null || isNaN(n)) return '';
    return 'BDT ' + Number(n).toLocaleString();
  }

  function extractMeta(html) {
    // Try parsing a hidden <pre class="sb-product-meta-raw"> JSON block first.
    try {
      var parser = new DOMParser();
      var doc = parser.parseFromString(html, 'text/html');
      var raw = doc.querySelector('.sb-product-meta-raw');
      if (raw) {
        var json = raw.textContent.trim();
        if (json) return JSON.parse(json);
      }
    } catch (e) {}
    // Fallback: try [key: value] markers in the content
    var meta = {};
    var rx = /\[(\w+)\s*:\s*([^\]]+)\]/g, m;
    while ((m = rx.exec(html)) !== null) meta[m[1].toLowerCase()] = m[2].trim();
    if (meta.price) meta.price = Number(meta.price);
    if (meta.discount_price) meta.discount_price = Number(meta.discount_price);
    return meta;
  }

  function postToProduct(entry) {
    var title = (entry.title && entry.title.$t) || '';
    var url = '';
    (entry.link || []).forEach(function (l) { if (l.rel === 'alternate') url = l.href; });
    var thumb = (entry.media$thumbnail && entry.media$thumbnail.url) || '';
    if (thumb) thumb = thumb.replace(/\/s72-c\//, '/s600/');
    var summary = (entry.summary && entry.summary.$t) || (entry.content && entry.content.$t) || '';
    var meta = extractMeta(summary);
    var labels = (entry.category || []).map(function (c) { return c.term; });
    return {
      title: title,
      url: url,
      image: meta.image || thumb,
      images: meta.images || (thumb ? [thumb] : []),
      price: meta.price,
      discount_price: meta.discount_price,
      badge: meta.badge,
      category: meta.category,
      labels: labels,
      summary: summary,
    };
  }

  function fetchFeed(label, max, cb) {
    var url = (location.origin) + (CONFIG.feedUrl || '/feeds/posts/summary') +
      (label ? '/-/' + encodeURIComponent(label) : '') +
      '?alt=json&max-results=' + (max || 12);
    fetch(url, { credentials: 'omit' })
      .then(function (r) { return r.json(); })
      .then(function (j) {
        var entries = (j && j.feed && j.feed.entry) || [];
        cb(entries.map(postToProduct));
      })
      .catch(function () { cb([]); });
  }

  function productCard(p) {
    var price = p.discount_price != null ? p.discount_price : p.price;
    var hasDiscount = p.discount_price != null && p.price != null && p.discount_price < p.price;
    var badge = p.badge ? '<span class="absolute top-2 left-2 px-2 py-0.5 rounded-full bg-primary text-white text-[10px] font-bold uppercase tracking-wider">' + p.badge + '</span>' : '';
    var img = p.image || 'https://www.shokherbikewala.com/logo.png';
    return (
      '<a href="' + p.url + '" class="sb-product-card sb-reveal group block rounded-2xl glass border border-line overflow-hidden">' +
        '<div class="relative aspect-square bg-bg-2 overflow-hidden">' +
          badge +
          '<img alt="' + p.title.replace(/"/g, '&quot;') + '" loading="lazy" class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" src="' + img + '"/>' +
        '</div>' +
        '<div class="p-3 sm:p-4">' +
          '<h3 class="text-sm sm:text-base font-bold leading-snug line-clamp-2 text-fg min-h-[2.5em]">' + p.title + '</h3>' +
          '<div class="mt-1.5 flex items-baseline gap-2">' +
            (price != null ? '<span class="text-primary font-extrabold">' + fmtPrice(price) + '</span>' : '<span class="text-fg-soft text-xs">Price on request</span>') +
            (hasDiscount ? '<span class="text-xs text-fg-soft line-through">' + fmtPrice(p.price) + '</span>' : '') +
          '</div>' +
        '</div>' +
      '</a>'
    );
  }

  function categoryCard(c) {
    var labelUrl = location.origin + '/search/label/' + encodeURIComponent(c.slug);
    return (
      '<a href="' + labelUrl + '" class="sb-product-card sb-reveal group block rounded-2xl glass border border-line overflow-hidden">' +
        '<div class="aspect-[4/3] bg-bg-2 overflow-hidden">' +
          '<img alt="' + c.name + '" loading="lazy" class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" src="' + c.image + '"/>' +
        '</div>' +
        '<div class="p-3 text-center">' +
          '<div class="font-bold text-fg text-sm sm:text-base">' + c.name + '</div>' +
          '<div class="text-[11px] text-fg-soft mt-0.5">Shop now &#8594;</div>' +
        '</div>' +
      '</a>'
    );
  }

  function renderGrid(targetId, items, renderer, emptyMsg) {
    var grid = document.getElementById(targetId);
    if (!grid) return;
    if (!items.length) {
      grid.innerHTML = '<p class="col-span-full text-center text-fg-soft py-12">' + (emptyMsg || 'Nothing here yet — check back soon.') + '</p>';
      return;
    }
    grid.innerHTML = items.map(renderer).join('');
    grid.querySelectorAll('.sb-reveal').forEach(watch);
  }

  // ===== Homepage =====
  var catGrid = document.getElementById('sb-categories-grid');
  if (catGrid && Array.isArray(CONFIG.categories)) {
    renderGrid('sb-categories-grid', CONFIG.categories, categoryCard);
  }
  var prodGrid = document.getElementById('sb-products-grid');
  if (prodGrid) {
    fetchFeed(CONFIG.productLabel || 'product', 8, function (items) {
      renderGrid('sb-products-grid', items, productCard, 'No products yet — add a Blogger post with label "product".');
    });
  }

  // ===== Label search =====
  var labelGrid = document.getElementById('sb-label-grid');
  if (labelGrid) {
    // Extract label from URL
    var m = location.pathname.match(/\/search\/label\/([^/?]+)/);
    var label = m ? decodeURIComponent(m[1]) : (CONFIG.productLabel || 'product');
    fetchFeed(label, 24, function (items) {
      renderGrid('sb-label-grid', items, productCard, 'No products in this collection yet.');
    });
  }

  // ===== Search query =====
  var searchGrid = document.getElementById('sb-search-grid');
  if (searchGrid) {
    var q = new URLSearchParams(location.search).get('q') || '';
    var qLower = q.toLowerCase();
    fetchFeed(CONFIG.productLabel || 'product', 50, function (items) {
      var filtered = items.filter(function (p) {
        return p.title.toLowerCase().indexOf(qLower) !== -1;
      });
      renderGrid('sb-search-grid', filtered, productCard, 'No results for "' + q + '".');
    });
  }

  // ===== Product detail enrichment =====
  var galleryMain = document.getElementById('sb-product-main-image');
  if (galleryMain) {
    // Parse meta from the rendered post body in the DOM
    var bodyEl = document.querySelector('.sb-prose');
    var meta = bodyEl ? extractMeta(bodyEl.innerHTML) : {};
    // Title is rendered by Blogger; price/images/etc come from meta.
    var firstImg = bodyEl && bodyEl.querySelector('img');
    var images = (meta.images && meta.images.length)
      ? meta.images
      : (meta.image ? [meta.image] : (firstImg ? [firstImg.src] : []));
    if (images.length) {
      galleryMain.src = images[0];
      var thumbs = document.getElementById('sb-product-thumbs');
      if (thumbs && images.length > 1) {
        thumbs.innerHTML = images.map(function (src, i) {
          return '<button type="button" data-src="' + src + '" class="aspect-square rounded-lg overflow-hidden border border-line bg-bg-2 hover:border-primary/60' + (i === 0 ? ' ring-2 ring-primary' : '') + '"><img src="' + src + '" alt="" class="w-full h-full object-cover"/></button>';
        }).join('');
        thumbs.addEventListener('click', function (e) {
          var b = e.target.closest('button[data-src]');
          if (!b) return;
          galleryMain.src = b.getAttribute('data-src');
          thumbs.querySelectorAll('button').forEach(function (x) { x.classList.remove('ring-2', 'ring-primary'); });
          b.classList.add('ring-2', 'ring-primary');
        });
      }
    }

    // Price
    var priceEl = document.getElementById('sb-product-price');
    if (priceEl) {
      var p = meta.price, dp = meta.discount_price;
      if (dp != null && p != null && dp < p) {
        priceEl.innerHTML =
          '<span class="text-3xl font-display font-extrabold text-primary">' + fmtPrice(dp) + '</span>' +
          '<span class="text-base text-fg-soft line-through">' + fmtPrice(p) + '</span>' +
          '<span class="px-2 py-0.5 rounded-full bg-primary/10 text-primary text-xs font-bold">' + Math.round(((p - dp) / p) * 100) + '% off</span>';
      } else if (p != null) {
        priceEl.innerHTML = '<span class="text-3xl font-display font-extrabold text-primary">' + fmtPrice(p) + '</span>';
      } else {
        priceEl.innerHTML = '<span class="text-fg-soft">Price on request</span>';
      }
    }

    // Stock
    if (String(meta.in_stock).toLowerCase() === 'false') {
      var stockEl = document.getElementById('sb-product-stock');
      if (stockEl) {
        stockEl.className = 'inline-flex items-center gap-2 px-3 py-1 rounded-full bg-red-500/10 text-red-600 text-xs font-bold';
        stockEl.textContent = 'Out of stock';
      }
    }

    // Hook Buy Now -> /p/checkout.html?product=<slug>
    var slugFromUrl = (location.pathname.split('/').pop() || '').replace(/\.html$/, '');
    var buyBtn = document.getElementById('sb-buy-now');
    if (buyBtn) {
      var sep = buyBtn.href.indexOf('?') === -1 ? '?' : '&';
      buyBtn.href = buyBtn.href + sep + 'product=' + encodeURIComponent(slugFromUrl) +
        '&title=' + encodeURIComponent(document.title.split(' - ')[0]) +
        (meta.price != null ? '&price=' + encodeURIComponent(meta.discount_price != null ? meta.discount_price : meta.price) : '');
    }

    // Hook WhatsApp text
    var wa = document.getElementById('sb-whatsapp-order');
    if (wa) {
      var title = document.title.split(' - ')[0];
      var price = meta.discount_price != null ? meta.discount_price : meta.price;
      var msg = 'Hi! I want to order: ' + title + (price != null ? ' (' + fmtPrice(price) + ')' : '') + '\nLink: ' + location.href;
      wa.href = 'https://wa.me/8801518934708?text=' + encodeURIComponent(msg);
    }
  }
})();
//
